app.views.help=Backbone.View.extend({
	initialize:function(){console.log("initializing help view")},
	
	render:function(){$(this.el).html(this.template());
		$(document).attr("title","TPS - Time Planning Schedule | "+this.language.type+" | "+this.language.lang);return this},
	
	destroy_view:function(){this.undelegateEvents();
		$(this.el).removeData().unbind();this.remove();Backbone.View.prototype.remove.call(this);app.global.helpView=null}})